        // 由于 n <= 10^9, n/2 <= 5*10^8, 我们可以安全地使用 long long 进行计算。
        int64_t target = n / 2;
        int64_t low = 1, high = 1000; // 1000^3 = 10^9, 足够大
        limit_a = 1;
        while (low <= high) {
            int64_t mid = low + (high - low) / 2;
            // 计算 mid^3. 注意溢出问题，但由于 target <= 5*10^8, mid^3 应该不会超过 2^63-1 
            // 只有当 mid > 1290 才有可能溢出 int64_t。
            __int128_t mid_cubed = (__int128_t)mid * mid * mid;
            if (mid_cubed <= target) {
                limit_a = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
    }

