    for (int64_t a = 1; a <= limit_a; ++a) {
        int64_t a_cubed = a * a * a;

        // b 从 a 开始，以保证 a <= b
        for (int64_t b = a; ; ++b) {
            int64_t b_cubed = b * b * b;

            // 计算 x = a^3 + b^3
            // 检查是否会溢出或超过 n
            // 由于 a <= limit_a, a^3 <= n/2. 
            // 如果 b > limit_a, b^3 可能会超过 n, 我们可以提前终止。
            if (b_cubed > n - a_cubed) {
                // 此时 a^3 + b^3 > n
                break; 
            }

            int64_t x = a_cubed + b_cubed;

            if (x > n) {
                break;
            }

            // 统计这个和出现的次数
            sum_counts[x]++;
        }
    }

    // 收集所有出现次数 >= 2 的和
