    // Map to store the count of representations for each sum x = a^3 + b^3
    // Key: x, Value: count of pairs (a, b) such that a^3 + b^3 = x and a <= b
    std::map<Int64, int> sum_counts;

    // Determine the maximum possible value for 'a' or 'b'.
    // Since a^3 + b^3 <= n and a <= b, the maximum value occurs when a=b, so 2*b^3 <= n.
    // b^3 <= n / 2.
    // A safer upper bound is when a=1, b^3 <= n - 1. b <= cbrt(n).
    // Since n <= 10^9, cbrt(10^9) = 1000. We can use a slightly larger safe bound.
    // Let's iterate 'a' up to the point where a^3 + (a+1)^3 might exceed n.
    // Since a <= b, a^3 + b^3 >= 2 * a^3. So 2 * a^3 <= n, a^3 <= n/2.
    // Max_a is around cbrt(n/2). For n=10^9, n/2 = 5*10^8. cbrt(5*10^8) approx 793.

    // We iterate 'a' starting from 1.
    for (Int64 a = 1; ; ++a) {
        // Calculate a^3. Use Int64 for calculations.
        Int64 a3 = a * a * a;

        // Check if even the smallest possible sum with a (i.e., a^3 + a^3 = 2*a^3) exceeds n.
        if (2 * a3 > n) {
            break;
        }

        // Iterate 'b' starting from 'a' (since a <= b).
        for (Int64 b = a; ; ++b) {
            // Calculate b^3. Check for potential overflow if n were larger, but for n<=10^9,
            // b <= 1000, so b^3 fits in Int64.
            Int64 b3 = b * b * b;

            // Calculate the sum. Check for overflow before addition (though unlikely here).
            if (b3 > n - a3) {
                // a^3 + b^3 > n, so further increments of b will also exceed n. Break inner loop.
                break;
            }

            Int64 sum = a3 + b3;

            // Since we break when sum > n, this sum is <= n.
            sum_counts[sum]++;

            // Optimization: If b is already large enough such that even the next step (b+1)
            // will definitely exceed n when combined with the smallest possible 'a' (which is 1),
            // we can potentially break the outer loop early, but the outer loop condition handles this better.
            // We rely on the break condition above to stop the inner loop.
        }
